formula_scripts.beforeSaveApiScript:
// Only act when Mentor Status is Active
ifThen(
  mentorStatus == 'Active',

  // Set Mentor Start Date to today if not already set
  ifThen(
    mentorStartDate == null,
    mentorStartDate = datetime\today()
  );

  // Ensure the Contact's Assigned User is the mentor's own User account
  $contactId = contactRecordId;
  ifThen(
    $contactId != null,

    $userId = record\findOne('User', 'createdAt', 'asc', 'contactId=', $contactId);
    ifThen(
      $userId != null,
      $currentAssigned = record\attribute('Contact', $contactId, 'assignedUserId');
      ifThen(
        $currentAssigned != $userId,
        record\update('Contact', $contactId, 'assignedUserId', $userId)
      )
    )
  )
);
